### 1ÔłŹ‚É£ Basic WP-CLI setup

```
if ( defined('WP_CLI') && WP_CLI ) {

    class Choir_CLI {

        /**
         * Migrate data from one environment to another.
         *
         * ## OPTIONS
         *
         * <from>
         * : Source environment (e.g., staging)
         *
         * <to>
         * : Destination environment (e.g., live)
         *
         * ## EXAMPLES
         *
         *     wp choir:migrate staging live
         */
        public function migrate( $args, $assoc_args ) {

            list( $from, $to ) = $args;

            WP_CLI::line("Starting migration from {$from} ‚Üí {$to}...");

            // 1. Set DB credentials for source and target
            $source_db = $this->get_db_info( $from );
            $target_db = $this->get_db_info( $to );

            if ( ! $source_db || ! $target_db ) {
                WP_CLI::error('Invalid source or target environment.');
            }

            // 2. Export Koko tables from source
            WP_CLI::line("Exporting Koko tables from {$from}...");
            $tables_raw = shell_exec(
                "wp db query \"SHOW TABLES LIKE 'wp_koko%';\" --url={$source_db['url']} --skip-column-names"
            );
            $tables = preg_split('/\s+/', trim($tables_raw));
            $table_list = implode(' ', $tables);

            $dump_file = "/tmp/koko_{$from}_to_{$to}_" . date('Ymd_His') . ".sql";
            WP_CLI::runcommand("wp db export {$dump_file} --tables={$table_list} --url={$source_db['url']} --add-drop-table");
            WP_CLI::line("Exported to {$dump_file}");

            // 3. Import into target
            WP_CLI::line("Importing into {$to}...");
            WP_CLI::runcommand("wp db import {$dump_file} --url={$target_db['url']}");
            WP_CLI::success("Migration completed from {$from} ‚Üí {$to}!");
        }

        /**
         * Return DB info for a given environment
         */
        private function get_db_info( $env ) {
            $config = [
                'local' => ['url' => 'https://local.xxx.nl'],
                'staging' => ['url' => 'https://staging.xxx.nl'],
                'live' => ['url' => 'https://xxx.nl'],
            ];

            return $config[ $env ] ?? null;
        }
    }

    WP_CLI::add_command( 'choir', 'Choir_CLI' );
}
```

