```
<?php

use Monolog\Logger;

/**
 * Smart logger for WordPress + WP-CLI.
 *
 * @param string $level   debug|info|notice|warning|error|critical
 * @param string $message Log message.
 * @param array  $context Optional structured data.
 */
function log_msg(string $level, string $message, array $context = []): void
{
    static $logger = null;

    // Lazily initialize logger once
    if ($logger === null) {
        if (!class_exists('\Monolog\Logger')) {
            error_log("Monolog not available: $message");
            return;
        }

        $logger = choir_logger(); // factory (see below)
    }

    // Normalize level
    $monologLevel = match (strtolower($level)) {
        'debug'     => Logger::DEBUG,
        'info'      => Logger::INFO,
        'notice'    => Logger::NOTICE,
        'warning'   => Logger::WARNING,
        'error'     => Logger::ERROR,
        'critical'  => Logger::CRITICAL,
        default     => Logger::INFO
    };

    // Log to file
    $logger->log($monologLevel, $message, $context);

    // Print to CLI if running wp-cli
    if (defined('WP_CLI') && WP_CLI) {
        $prefix = strtoupper($level);

        if ($monologLevel >= Logger::ERROR) {
            WP_CLI::error("[$prefix] $message", false);
        } elseif ($monologLevel >= Logger::WARNING) {
            WP_CLI::warning("[$prefix] $message");
        } else {
            WP_CLI::line("[$prefix] $message");
        }
    }
}
```

* * *

Logger Factory (clean + centralized)
====================================

Put this in `src/helpers/logger.php`:

```
<?php

use Monolog\Logger;
use Monolog\Handler\StreamHandler;
use Monolog\Formatter\LineFormatter;

function choir_logger(): Logger
{
    static $instance = null;

    if ($instance !== null) {
        return $instance;
    }

    $logDir = WP_CONTENT_DIR . '/logs';
    if (!is_dir($logDir)) {
        mkdir($logDir, 0755, true);
    }

    $level = (defined('ENVIRONMENT') && ENVIRONMENT === 'live')
        ? Logger::WARNING
        : Logger::DEBUG;

    $handler = new StreamHandler("$logDir/choir.log", $level);

    // Nice readable format (timestamp + level + message)
    $format = "[%datetime%] %level_name%: %message% %context%\n";
    $handler->setFormatter(new LineFormatter($format, null, true, true));

    $logger = new Logger('choir');
    $logger->pushHandler($handler);

    $instance = $logger;
    return $logger;
}
```

