function choir_logger(): Logger
{
    static $instance = null;

    if ($instance !== null) {
        return $instance;
    }

    $logger = new Logger('choir');

    $level = (defined('ENVIRONMENT') && ENVIRONMENT === 'live')
        ? Logger::WARNING
        : Logger::DEBUG;

    $dateFormat = "Y-m-d H:i:s";
    $format = "[%datetime%] %level_name%: %message% %context%\n";
    $formatter = new LineFormatter($format, $dateFormat, true, true);

    $logDir = WP_CONTENT_DIR . '/logs';
    $logFile = "$logDir/choir.log";

    $fileHandlerAdded = false;

    // Try to create the logs directory if missing
    if (!is_dir($logDir)) {
        @mkdir($logDir, 0755, true);
    }

    // If directory exists and is writable, try file logging
    if (is_dir($logDir) && is_writable($logDir)) {
        try {
            $handler = new StreamHandler($logFile, $level, true);
            $handler->setFormatter($formatter);
            $logger->pushHandler($handler);
            $fileHandlerAdded = true;
        } catch (\Exception $e) {
            // Will fall back to STDERR / console below
        }
    }

    // Fallback: log to terminal (WP-CLI or PHP error output)
    if (!$fileHandlerAdded) {
        if (defined('WP_CLI') && WP_CLI) {
            $handler = new \Monolog\Handler\StreamHandler('php://stdout', $level);
        } else {
            $handler = new \Monolog\Handler\ErrorLogHandler();
        }

        $handler->setFormatter($formatter);
        $logger->pushHandler($handler);

        // Make failure visible
        $logger->warning("Could not write to log directory: $logDir ‚Äď using fallback logger.");
    }

    // Set correct timezone
    $logger->setTimezone(new DateTimeZone('Europe/Amsterdam'));

    $instance = $logger;
    return $logger;
}
```

