private function run_wp_command(string $command, string $label = ''): string
{
    log_debug("Running: $command");

    $output = WP_CLI::runcommand($command, [
        'return'     => true,
        'exit_error' => false,
    ]);

    $lines = preg_split("/\R/", trim($output));
    $last  = end($lines);

    log_info(($label ?: 'Command') . " result: $last");

    $exit = WP_CLI::get_runner()->get_exit_code();

    if ($exit !== 0) {
        log_error("Command failed (exit {$exit}):\n$output");
        WP_CLI::error("Failure: {$command}");
    }

    return $output;
}
