/**
 * Generic log wrapper that allows null messages.
 *
 * @param string      $level   Logging level: debug|info|notice|warning|error|critical
 * @param string|null $message Log message (null will be converted to empty string)
 * @param array       $context Optional context array
 */
function log_safe(string $level, ?string $message, array $context = []): void {
    $message = $message ?? ''; // convert null to empty string
    log_msg($level, $message, $context);
}

// Specific shortcuts
function log_debug(?string $message, array $context = []): void {
    log_safe('debug', $message, $context);
}

function log_info(?string $message, array $context = []): void {
    log_safe('info', $message, $context);
}

function log_notice(?string $message, array $context = []): void {
    log_safe('notice', $message, $context);
}

// etc for warning, error, critical
```

### Advantages

1.  You can pass `null` to any log function safely.
2.  Keeps all existing code that uses `log_debug`/`log_info` unchanged.
3.  Centralizes the ‚Äúnull to empty string‚ÄĚ behavior in one place.
4.  Works nicely in CLI scripts where sometimes variables might be uninitialized.

Example usage:

```
$some_variable = null;
log_debug($some_variable); // ‚úÖ won't throw TypeError
log_info("Processing complete."); // ‚úÖ normal logging
```

