function choir_logger(): Logger {
    static $instance = null;

    if ($instance) return $instance;

    $logDir = WP_CONTENT_DIR . '/logs';

    if (!is_dir($logDir)) {
        mkdir($logDir, 0755, true);
    }

    $level = (defined('ENVIRONMENT') && ENVIRONMENT === 'live')
        ? Logger::WARNING
        : Logger::DEBUG;

    $handler = new StreamHandler("$logDir/choir.log", $level);

    $formatter = new LineFormatter(
        "[%datetime%] %level_name%: %message% %context%\n",
        "Y-m-d H:i:s",
        true, true
    );

    $handler->setFormatter($formatter);

    $logger = new Logger('choir');
    $logger->pushHandler($handler);
    $logger->setTimezone(new DateTimeZone('Europe/Amsterdam'));

    return $instance = $logger;
}
```

‚úÖ works both in CLI and browser  
‚úÖ no WP\_CLI dependency  
‚úÖ single instance  
