private function loadDomainContext(Domain $domain): DomainContext
{
    $configPath = $domain->wpConfigPath();

    if (!file_exists($configPath)) {
        WP_CLI::error("Config file not found: {$configPath}");
    }

    require $configPath;

    foreach (['db_name', 'db_user', 'db_password'] as $var) {
        if (!isset($$var)) {
            WP_CLI::error("Missing {$var} in {$configPath}");
        }
    }

    return new DomainContext(
        domain: $domain,
        dbName: $db_name,
        dbUser: $db_user,
        dbPassword: $db_password,
        dbHost: $db_host ?? 'localhost'
    );
}
```

