enum Domain: string {
    case LOCAL = 'local';
    case STAGING = 'staging';
    case LIVE = 'live';

    /**
     * Detect the current domain/host dynamically
     * 
     * @param array<Domain, string> $hostnames Optional mapping, defaults to DomainEnvironment::hostnames()
     */
    public static function detect_current(array $hostnames = []): ?self {
        $host = $_SERVER['HTTP_HOST'] ?? null;
        if (!$host) {
            return null; // Can't detect without host
        }

        if (empty($hostnames)) {
