    public function test_creates_local_environment_by_default(): void {
        $env = new FakeEnvReader([]);
        $factory = new DomainEnvironmentFactory($env);

        $domainEnv = $factory->create();

        $this->assertSame(Domain::LOCAL, $domainEnv->domain);
