    public function test_creates_staging_environment(): void {
        $env = new FakeEnvReader([
            'WP_ENV' => 'staging',
        ]);

        $factory = new DomainEnvironmentFactory($env);
        $domainEnv = $factory->create();

        $this->assertSame(Domain::STAGING, $domainEnv->domain);
    }
}
```

