    $dockerDir . '/base.yml',
    $dockerDir . '/local.yml',
];

// Build the docker compose -f ... -f ... --env-file ... command
$composeArgs = implode(' ', array_map(fn($f) => "-f " . escapeshellarg($f), $composeFiles));
$cmd = sprintf(
    'cd %s && docker compose %s --env-file %s up -d',
    escapeshellarg($projectRoot),
    $composeArgs,
    escapeshellarg($envFile)
);

echo "Running: $cmd\n";
passthru($cmd);
```

