```
$runner = new DockerComposeRunner(
    executor: $executor,
    docker: $local_docker,
    logger: $logger
);

$cmd = new WpCliCommand(['db', 'export', '/tmp/db.sql', '--url=http://localhost:8080']);
$runner->run($cmd); // --skip-ssl will be appended automatically
```

