```
final class ShellRunner implements CommandRunner
{
    public function __construct(private MigrationLogger $logger) {}

    public function run(CliCommand $command): CommandResult
    {
        $cmdStr = implode(' ', $command->args());
        $this->logger->debug("Running shell command: $cmdStr");

        if ($command->dryRun()) {
            return new CommandResult(command: $cmdStr, executed: false, exitcode: 0, stdout: '', stderr: '');
        }

        exec($cmdStr . ' 2>&1', $output, $exitCode);

        return new CommandResult(
            command: $cmdStr,
            executed: true,
            exitcode: $exitCode,
            stdout: implode("\n", $output),
            stderr: '', // or handle separately if needed
        );
    }
}
```

