```
final class RunnerFactory
{
    public function __construct(
        private readonly DockerComposeContext $docker,
        private readonly MigrationLogger $logger,
        private readonly bool $dryRun
    ) {}

    public function make(bool $isDocker, string $service, string $mode): CommandRunner
    {
        $executor = $this->dryRun
            ? new DryRunExecutor($this->logger)
            : new ProcessExecutor($this->logger);

        if ($isDocker) {
            return match($mode) {
                'exec' => new DockerExecRunner(
                            executor: $executor,
                            docker: $this->docker,
                            service: $service,
                            logger: $this->logger,
                          ),
                'run'  => new DockerRunRunner(
                            executor: $executor,
                            docker: $this->docker,
                            service: $service,
                            logger: $this->logger,
                          ),
            };
        }

        // fallback for bare-metal / webhost
        return new HostProcessRunner(
            executor: $executor,
            service: $service,
            logger: $this->logger,
        );
    }
}
```

