final class RunnerFactory
{
    /**
     * @param array<string, DockerEnvContext> $environments
     */
    public function __construct(
        private bool $isDocker,
        private array $environments,   // e.g. ['source' => ..., 'target' => ...]
        private MigrationLogger $logger,
        private bool $dryRun
    ) {}

    public function make(string $service, ExecutionMode $mode, string $envName): CommandRunner
    {
        $executor = $this->dryRun
            ? new DryRunExecutor($this->logger)
            : new ProcessExecutor($this->logger);

        if (! $this->isDocker) {
            return new HostRunner($executor, $this->logger);
        }

        $docker = $this->environments[$envName]->docker;

        return match ($mode) {
            ExecutionMode::RUN  => new DockerRunRunner(
                executor: $executor,
                docker: $docker,
                service: $service,
                logger: $this->logger,
            ),
            ExecutionMode::EXEC => new DockerExecRunner(
                executor: $executor,
                docker: $docker,
                service: $service,
                logger: $this->logger,
            ),
        };
    }
}
```

