4ÔłŹ‚É£ Example `DockerExecRunner`
------------------------------

```
class DockerExecRunner implements MysqlRunner {
    public function __construct(
        protected string $service,
        protected CommandExecutor $executor
    ) {}

    public function runMysql(MysqlCommand $command, string $database): CommandResult {
        $args = array_merge(
            ['mysql', '-D', $database],
            $command->getArgs()
        );

        $cmdStr = $this->buildDockerCommand($args, $command->env);

        return $this->executor->execute($cmdStr);
    }

    protected function buildDockerCommand(array $args, array $env): string {
        $envFlags = implode(' ', array_map(fn($k,$v)=>"-e $k='".addslashes($v)."'",$env,array_keys($env)));
        return sprintf('docker exec %s %s %s', $this->service, $envFlags, implode(' ', $args));
    }
}
```

