final class MigrationContext {

    private array $planned_artifacts = [];

    public function __construct(
        private readonly MigrationState $state,
        private readonly DomainEnvironment $source,
        private readonly DomainEnvironment $target,
        private readonly MigrationWorkspace $workspace,
        private readonly MigrationTimestamp $timestamp,
        private readonly bool $dry_run,
    ) {}

    // Expose read-only accessors
    public function state(): MigrationState { return $this->state; }
    public function source(): DomainEnvironment { return $this->source; }
    public function target(): DomainEnvironment { return $this->target; }
    public function workspace(): MigrationWorkspace { return $this->workspace; }
    public function timestamp(): MigrationTimestamp { return $this->timestamp; }
    public function dryRun(): bool { return $this->dry_run; }

    public function plannedArtifacts(): array { return $this->planned_artifacts; }

    // Controlled update, returns new context
    public function withArtifact(object $artifact): self {
        $new = clone $this;
        $new->planned_artifacts = [...$this->planned_artifacts, $artifact];
        return $new;
    }
}
```

