final class MigrationScript {

    public function __construct(private array $argv) {
        // 1ÔłŹ‚É£ Determine source/target domains
        $source = $argv['source'] ?? Domain::STAGING->value;
        $target = $argv['target'] ?? Domain::LOCAL->value;

        // 2ÔłŹ‚É£ Optionally load DockerEnv early (if running on Docker)
        $docker_env_source = DockerContexts::is_docker() 
            ? DockerContexts::for($source)->env() 
            : null;
        $docker_env_target = DockerContexts::is_docker() 
            ? DockerContexts::for($target)->env() 
            : null;

        // 3ÔłŹ‚É£ Build immutable DomainEnvironments
        $source_env = DomainEnvironmentFactory::from_docker_env($docker_env_source, Domain::from($source));
        $target_env = DomainEnvironmentFactory::from_docker_env($docker_env_target, Domain::from($target));

        // 4ÔłŹ‚É£ Build immutable MigrationWorkspace
        $workspace = $this->build_workspace($target_env);

        // 5ÔłŹ‚É£ Build immutable MigrationContext
        $context = new MigrationContext(
            state: new MigrationState(),
            source: $source_env,
            target: $target_env,
            workspace: $workspace,
            timestamp: new MigrationTimestamp(),
            dry_run: $argv['dry_run'] ?? false,
        );

        // 6ÔłŹ‚É£ Logger (can reference context)
        $logger = $this->build_logger($context, $argv['log_level'] ?? 'info');

        // 7ÔłŹ‚É£ RunnerFactory has the context, uses DomainEnvs from context
        $runner_factory = new RunnerFactory(
            is_docker: DockerContexts::is_docker(),
            context: $context,
            logger: $logger,
