final class DomainEnvironmentFactory {

    public static function all(): array {
        return [
            Domain::LOCAL->value   => self::local(),
            Domain::STAGING->value => self::staging(),
            Domain::LIVE->value    => self::live(),
        ];
    }

    public static function local(): DomainEnvironment {
        $inside = running_inside_docker();

        $db = new DatabaseConfig(
            data_source_name: getenv('MYSQL_DATABASE') ?: 'localchoir',
            db_user: getenv('MYSQL_USER') ?: 'root',
            db_password: getenv('MYSQL_PASSWORD') ?: '',
            host: $inside ? 'db' : '127.0.0.1', // container network vs host
        );

        return new DomainEnvironment(
            domain: Domain::LOCAL,
            database: $db,
            wordpress: new WordpressConfig(
                home_url:    getenv('WP_HOME') ?: 'http://localhost:8080',
                site_url:    getenv('WP_SITEURL') ?: 'http://localhost:8080',
                hostname:    getenv('WP_HOSTNAME') ?: 'localhost',
                content_url: getenv('WP_CONTENT_URL') ?: '/wordpress/wp_content',
            ),
        );
    }

    public static function staging(): DomainEnvironment {
        $inside = running_inside_docker();

        $db = new DatabaseConfig(
            data_source_name: getenv('STAGING_MYSQL_DATABASE') ?: 'staging_db',
            db_user: getenv('STAGING_MYSQL_USER') ?: 'staging_user',
            db_password: getenv('STAGING_MYSQL_PASSWORD') ?: 'secret',
            host: $inside ? 'staging_db_service' : 'staging.example.com',
        );

        return new DomainEnvironment(
            domain: Domain::STAGING,
            database: $db,
            wordpress: new WordpressConfig(
                home_url:    getenv('STAGING_WP_HOME') ?: 'http://staging.localhost',
                site_url:    getenv('STAGING_WP_SITEURL') ?: 'http://staging.localhost',
                hostname:    getenv('STAGING_WP_HOSTNAME') ?: 'staging.localhost',
                content_url: getenv('STAGING_WP_CONTENT_URL') ?: '/wordpress/wp_content',
            ),
        );
    }

    // similarly for live()
}
```

