```
<?php declare(strict_types=1);

namespace Choir\Migration\Environment;

final class DatabaseConfig
{
    public function __construct(
        private readonly string $data_source_name,
        private readonly string $db_user,
        private readonly string $db_password,
        private readonly string $host,          // can be "local_db" OR "local_db:3306"
    ) {}

    public function db_user(): string { return $this->db_user; }
    public function db_password(): string { return $this->db_password; }
    public function database(): string { return $this->data_source_name; }

    /**
     * Raw host value as provided by env/config (may include ":port").
     */
    public function host(): string { return $this->host; }

    /**
     * Hostname only (safe for `mysqldump -h`).
     */
    public function host_name(): string
    {
        [$host,] = $this->split_host_port($this->host);
        return $host;
    }

    /**
     * Port if present, otherwise null.
     */
    public function port(): ?int
    {
        [, $port] = $this->split_host_port($this->host);
        return $port;
    }

    /**
     * @return array{0:string,1:?int}
     */
    private function split_host_port(string $host): array
    {
        $host = trim($host);
        if ($host === '') {
            return ['', null];
        }

        // If you ever use IPv6 later, this will need to be extended.
        if (!str_contains($host, ':')) {
            return [$host, null];
        }

        [$h, $p] = explode(':', $host, 2);
        $h = trim($h);
        $p = trim($p);

        if ($h === '' || $p === '' || !ctype_digit($p)) {
            // If malformed, treat whole thing as hostname and ignore port.
            return [$host, null];
        }

        return [$h, (int)$p];
    }
}
```

